{
    key: "getPDSSearchQuery", value: function () {
        var n = ['name match "'.concat(this.queryToSearch, '"')];
        return this.filter && ("folder" === this.filter ? n.push('type = "'.concat(this.filter, '"'))
        : n.push('category = "'.concat(this.filter, '"'))), n.join(" and ")
    }
}
